solution_code:
#include <iostream>
#include <string>

int main() {
    int n;
    std::cin >> n;
    for (int i = 0; i < n; ++i) {
        std::string code;
        std::cin >> code;
        if (code == "UB") {
            std::cout << "undefined behavior\n";
        } else if (code == "RAII" || code == "SMART") {
            std::cout << "resource management\n";
        } else if (code == "HEADERS") {
            std::cout << "build system\n";
        } else if (code == "NAMESPACE") {
            std::cout << "naming\n";
        }
    }
    return 0;
}

