#include <iostream>
#include <string>

bool hasIncludeGuard(const std::string& pragma_once, const std::string& ifndef_guard) {
    return pragma_once == "yes" || ifndef_guard == "yes";
}

int main() {
    int n;
    std::cin >> n;
    for (int i = 0; i < n; ++i) {
        std::string pragma_once, ifndef_guard;
        std::cin >> pragma_once >> ifndef_guard;
        std::cout << (hasIncludeGuard(pragma_once, ifndef_guard) ? "guarded" : "unguarded") << '\n';
    }
    return 0;
}
